__global__ void rank16_add_scalar_kernel(float* __restrict__ y,
                                         const float* __restrict__ A,
                                         const float* __restrict__ T,
                                         int64_t d) {
    const int64_t total = d * d;
    const int64_t stride = static_cast<int64_t>(blockDim.x) * gridDim.x;
